const categoriaUrl = $('Loop Over categories').item.json.categoria_url;
const productosUrls = $input.item.json.producto_url;

const categoria = categoriaUrl.match(/\/categoria-producto\/([^/]+)\/?$/)?.[1] || '';

return productosUrls.map(url => ({
  json: {
    categoria: categoria,
    producto_url: url
  }
}));

// ============================================================
// NODO 3: Características normalizadas
// Responsabilidad: parsear el HTML de "caracteristicas" 
//
// Subcasos cubiertos:
//   1. <p> con viñetas • + <br>            → features
//   2. <strong>Título</strong><br>texto    → features_kv
//   3. <li> con <strong> interno           → features_kv con key/value
//   4. <li> atributo:valor                 → features_kv
//   5. "Homologado con:" + lista           → compatibility {brand, models}
//   6. Múltiples secciones heading+lista   → sections[]
//   7. Tablas con listas en celdas         → table_specs
//   8. Notas de reemplazo / CTA            → descarta CTA, extrae replacement_notes
//   9. Sub-valores con <br> dentro de <li> → split individual
//  10. Variantes/modelos ("X: ofrece Y")   → variants
//  11. Tablas HTML con celdas únicas       → auto-asigna a desc/features
// Salida final:
//   - compatibility
//   - table_specs
//   - variants
//   - features_text
//
// Nota importante:
//   - Las notas tipo "reemplaza al equipo X" NO salen como campo
//     separado; se integran en description para que no se pierdan
//     en el embedding.
//   - features, features_kv, sections, description y kit_contents
//     se usan solo internamente para construir features_text.
// ============================================================


// --- Utilidades ---

function decodeHtml(text) {
  if (!text) return '';
  return String(text)
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&lt;/gi, '<')
    .replace(/&gt;/gi, '>')
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, "'")
    .replace(/&apos;/gi, "'");
}

function cleanText(text) {
  return decodeHtml(text)
    .replace(/\r/g, '')
    .replace(/[ \t]+/g, ' ')
    .replace(/ *\n */g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function stripAllTags(html) {
  return String(html || '')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/li>/gi, '\n')
    .replace(/<li[^>]*>/gi, '')
    .replace(/<\/p>/gi, '\n')
    .replace(/<p[^>]*>/gi, '\n')
    .replace(/<\/div>/gi, '\n')
    .replace(/<div[^>]*>/gi, '\n')
    .replace(/<\/tr>/gi, '\n')
    .replace(/<[^>]+>/g, '');
}

function stripHtml(html) {
  return cleanText(stripAllTags(html));
}

function stripHtmlAsValue(html) {
  const multiline = stripHtml(html);
  if (!multiline) return '';
  return multiline.split('\n').map(s => s.trim()).filter(Boolean).join(' | ');
}

// --- Filtros de ruido ---

const CTA_PATTERNS = [
  /si\s+necesita?\s+sim\s*cards?/i,
  /puede\s+solicitar(la|lo|las|los)?\s+(aqu[ií]|en\s+bismark)/i,   // ← corregido
  /pueden?\s+solicitar(la|lo|las|los)?\s+(aqu[ií]|en\s+bismark)/i, // ← corregido
  /plan\s+de\s+datos/i,
  /puede[ns]?\s+contactar/i,
  /solicít[ae]/i,
  /contáctenos/i,
  /para\s+mayor\s+información/i,
  /no\s+están?\s+incluid[oa]s?\s+en\s+el\s+paquete/i,
  /solicitar\s+bajo\s+demanda/i,
  /solicitud\s+bajo\s+demanda/i,
  /para\s+obtener\s+m[aá]s\s+aplicaciones/i,
  /visite\s+www\./i,
  /consulte\s+(la\s+)?información\s+de\s+pedidos/i,
  /para\s+m[aá]s\s+apps/i,
  /ver\s+sitio\s+web/i,
];


function isCTA(text) {
  const t = stripHtml(text);
  if (!t || t.length < 10) return false;
  return CTA_PATTERNS.some(p => p.test(t));
}

const REPLACEMENT_PATTERNS = [
  /este\s+(gateway|router|equipo|dispositivo)\s+reemplaza/i,
  /reemplaza\s+al\s+equipo/i,
];

function isReplacementNote(text) {
  const t = stripHtml(text);
  return REPLACEMENT_PATTERNS.some(p => p.test(t));
}

const EDITORIAL_NOISE = [
  /^borrar$/i,
  /^a[ñn]adir!+$/i,
  /^agregar!+$/i,
  /^(todo|tbd|pendiente)!*$/i,
];

function isEditorialNoise(text) {
  const t = stripHtml(text).trim();
  if (!t) return true;
  return EDITORIAL_NOISE.some(p => p.test(t));
}

// --- Detectores estructurales ---

const COMPATIBILITY_HEADING = [
  /homologado\s+con/i,
  /compatible\s+con/i,
  /certificad[oa]s?\s*(con|en|por|:)/i,
  /certificaciones\s+global/i,
];

const SECTION_HEADING = [
  /^homologado\s+con/i,
  /^compatible\s+con/i,
  /^certificad[oa]s?\s*(con|en|por)?/i,
  /^caracter[ií]sticas\s+clave/i,
  /^el\s+kit\s+est[aá]ndar\s+incluye/i,
  /^adem[aá]s\s+(los|el|la)?\s*(switch|router|equipo)/i,
];

function parseKV(text) {
  const t = stripHtml(text);
  const m = t.match(/^([^:–—]+?)\s*[:–—]\s+(.+)$/s);
  if (m && m[1].length < 80 && m[2].length > 0) {
    return { key: m[1].trim(), value: m[2].trim() };
  }
  return null;
}

function isVariantItem(text) {
  const t = stripHtml(text).trim();
  return /^[A-Z0-9][\w\-\s/()]+\s*[:]\s+ofrece/i.test(t) ||
         /^[A-Z0-9][\w\-\s/()]+\s+admite\s+/i.test(t);
}

// --- Extracción de bloques ---

function extractTopBlocks(html) {
  const source = String(html || '').trim();
  if (!source) return [];

  const blocks = [];
  const blockRegex = /<(ul|ol|table|div|p)(\s[^>]*)?>[\s\S]*?<\/\1>/gi;
  let lastIndex = 0;
  let match;

  while ((match = blockRegex.exec(source)) !== null) {
    if (match.index > lastIndex) {
      const between = source.slice(lastIndex, match.index).trim();
      if (between && stripHtml(between).length > 0) {
        blocks.push({ type: 'text', html: between, text: stripHtml(between) });
      }
    }
    blocks.push({ type: match[1].toLowerCase(), html: match[0], text: stripHtml(match[0]) });
    lastIndex = match.index + match[0].length;
  }

  if (lastIndex < source.length) {
    const rest = source.slice(lastIndex).trim();
    if (rest && stripHtml(rest).length > 0) {
      blocks.push({ type: 'text', html: rest, text: stripHtml(rest) });
    }
  }

  return blocks;
}

function extractListItems(ulHtml) {
  const items = [];
  const liRegex = /<li[^>]*>([\s\S]*?)<\/li>/gi;
  let m;
  while ((m = liRegex.exec(ulHtml)) !== null) {
    const text = stripHtml(m[1]);
    if (text) items.push({ html: m[1], text });
  }
  return items;
}

function parseStrongHeadingParagraph(pHtml) {
  const strongMatch = pHtml.match(/<strong[^>]*>([\s\S]*?)<\/strong>/i);
  if (!strongMatch) return null;

  const heading = stripHtml(strongMatch[1]).replace(/[:.]+$/, '').trim();
  if (!heading || heading.length > 120) return null;

  const body = stripHtml(
    pHtml
      .replace(/<strong[^>]*>[\s\S]*?<\/strong>/i, '')
      .replace(/^[\s]*<br\s*\/?>/i, '')
  );

  return { heading, body: body || '' };
}

// Parser local de tablas embebidas dentro del HTML de caracteristicas
function parseEmbeddedTable(tableHtml) {
  const rows = [...String(tableHtml).matchAll(/<tr[^>]*>([\s\S]*?)<\/tr>/gi)];
  const result = [];
  let currentSection = null;

  for (const rowMatch of rows) {
    const rowHtml = rowMatch[1];
    const cellMatches = [...rowHtml.matchAll(/<(t[dh])([^>]*)>([\s\S]*?)<\/\1>/gi)];

    if (cellMatches.length === 1) {
      const attrs = cellMatches[0][2] || '';
      const inner = cellMatches[0][3];

      if (/colspan\s*=\s*["']?\s*[2-9]/i.test(attrs) && /<strong/i.test(inner)) {
        const t = stripHtml(inner);
        if (t && !isEditorialNoise(t) && !isCTA(t)) currentSection = t;
      } else {
        const text = stripHtml(inner);
        if (text && !isEditorialNoise(text) && !isCTA(text)) {
          if (/<li/i.test(inner)) {
            const items = extractListItems(inner).map(it => it.text);
            items.forEach(it => result.push({ type: 'feature', value: it }));
          } else {
            result.push({ type: 'description', value: text });
          }
        }
      }
      continue;
    }

    const cells = cellMatches.map(m => ({
      html: m[3],
      text: stripHtml(m[3]),
      valueText: stripHtmlAsValue(m[3]),
    }));

    if (cells.length < 2) continue;
    if (cells.every(c => !c.text) || cells.every(c => isEditorialNoise(c.text))) continue;

    const name = cells[0].text;
    const valueHtml = cells[1].html;
    let value;
    let items = null;

    if (/<li/i.test(valueHtml)) {
      items = extractListItems(valueHtml).map(it => it.text);
      value = items.join(' | ');
    } else {
      value = cells.slice(1).map(c => c.valueText).filter(Boolean).join(' | ').trim();
    }

    if (!name || !value) continue;
    if (isEditorialNoise(name) || isEditorialNoise(value) || isCTA(value)) continue;

    const spec = { name, value };
    if (currentSection) spec.section = currentSection;
    if (items) spec.items = items;
    result.push(spec);
  }

  return result;
}

// --- Clasificación principal ---

function extractAndNormalize(html) {
  const out = {
    // internos para componer features_text
    features: [],
    features_kv: [],
    sections: [],
    description: [],
    kit_contents: [],

    // sí se exponen
    compatibility: [],
    variants: [],
    table_specs: [],
  };

  const source = String(html || '').trim();
  if (!source) return out;

  const blocks = extractTopBlocks(source);
  let currentSectionHeading = null;
  let expectingCompatibilityList = false;
  let expectingKitList = false;

  for (let i = 0; i < blocks.length; i++) {
    const block = blocks[i];

    // --- TABLA embebida ---
    if (block.type === 'table' || block.type === 'div') {
      const tableHtml = block.type === 'div'
        ? (block.html.match(/<table[\s\S]*?<\/table>/i) || [block.html])[0]
        : block.html;

      if (/<table/i.test(tableHtml)) {
        const parsedTableSpecs = parseEmbeddedTable(tableHtml);
        for (const spec of parsedTableSpecs) {
          if (spec.type === 'feature') out.features.push(spec.value);
          else if (spec.type === 'description') out.description.push(spec.value);
          else out.table_specs.push(spec);
        }
        continue;
      }
    }

    // --- PÁRRAFO o texto suelto ---
    if (block.type === 'p' || block.type === 'text') {
      const text = block.text;
      if (!text || text.replace(/[*\s]/g, '').length === 0) continue;
      if (isCTA(text)) continue;
      if (isEditorialNoise(text)) continue;

      // Las notas de reemplazo se preservan dentro de description
      if (isReplacementNote(text)) {
        out.description.push(text);
        continue;
      }

      const strongParsed = parseStrongHeadingParagraph(block.html);
      if (strongParsed) {
        const { heading, body } = strongParsed;

        if (COMPATIBILITY_HEADING.some(p => p.test(heading))) {
          expectingCompatibilityList = true;
          currentSectionHeading = null;
          if (body && !isCTA(body)) out.compatibility.push(body);
          continue;
        }

        if (/kit\s+est[aá]ndar/i.test(heading) || /incluye/i.test(heading)) {
          expectingKitList = true;
          currentSectionHeading = null;
          continue;
        }

        const nextBlock = blocks[i + 1];
        if (nextBlock && (nextBlock.type === 'ul' || nextBlock.type === 'ol')) {
          currentSectionHeading = heading;
          if (body && !isCTA(body)) out.description.push(body);
          continue;
        }

        if (body && body.length > 5 && !isCTA(body)) {
          out.features_kv.push({ key: heading, value: body });
        } else if (!body) {
          currentSectionHeading = heading;
        }
        continue;
      }

      const rawLines = block.html
        .replace(/<br\s*\/?>/gi, '\n')
        .replace(/<[^>]+>/g, '');
      const lines = decodeHtml(rawLines)
        .split('\n').map(l => l.trim()).filter(Boolean);

      const bullets = [];
      const nonBullets = [];

      for (const line of lines) {
        if (/^[•\-–]/.test(line)) bullets.push(line.replace(/^[•\-–]\s*/, '').trim());
        else nonBullets.push(line);
      }

      if (bullets.length > 0) {
        bullets.forEach(b => {
          if (!isCTA(b) && !isEditorialNoise(b)) out.features.push(b);
        });
        nonBullets.forEach(nb => {
          if (nb.length > 10 && !isCTA(nb) && !isEditorialNoise(nb)) {
            out.description.push(nb);
          }
        });
        continue;
      }

      const kv = parseKV(text);
      if (kv && kv.value.length > 10 && !isCTA(kv.value)) {
        out.features_kv.push(kv);
        continue;
      }

      if (text.length > 10) {
        if (SECTION_HEADING.some(p => p.test(text))) {
          currentSectionHeading = text;
          continue;
        }
        if (/^[\w]+[\s]*-[\s]*[A-Z]{2,}/m.test(text) && text.length < 100) {
          out.compatibility.push(text);
          continue;
        }
        out.description.push(text);
      }
      continue;
    }

    // --- LISTA ---
    if (block.type === 'ul' || block.type === 'ol') {
      const items = extractListItems(block.html);

      if (expectingCompatibilityList) {
        for (const item of items) {
          if (isCTA(item.text) || isEditorialNoise(item.text)) continue;
          const kv = parseKV(item.text);
          if (kv) out.compatibility.push({ brand: kv.key, models: kv.value });
          else out.compatibility.push(item.text);
        }
        expectingCompatibilityList = false;
        continue;
      }

      if (expectingKitList) {
        for (const item of items) {
          if (!isCTA(item.text) && !isEditorialNoise(item.text)) {
            out.kit_contents.push(item.text);
          }
        }
        expectingKitList = false;
        continue;
      }

      const sectionHeading = currentSectionHeading;
      currentSectionHeading = null;
      const sectionItems = [];

      for (const item of items) {
        if (isCTA(item.text) || isEditorialNoise(item.text)) continue;

        if (isVariantItem(item.text)) {
          out.variants.push(item.text);
          continue;
        }

        const kv = parseKV(item.text);
        const isLikelyKV = kv && kv.key.split(/\s+/).length <= 6 &&
          !/^(soporta|admite|compatible|permite|incluye|proporciona)/i.test(kv.key);

        if (isLikelyKV) {
          const strongInLi = item.html.match(/<strong[^>]*>([\s\S]*?)<\/strong>/i);
          if (strongInLi) {
            const strongKey = stripHtml(strongInLi[1]).replace(/[:.]+$/, '').trim();
            const strongBody = stripHtml(
              item.html.replace(/<strong[^>]*>[\s\S]*?<\/strong>/i, '').replace(/^[\s]*<br\s*\/?>/i, '')
            );
            const kvObj = { key: strongKey, value: strongBody || kv.value };
            if (sectionHeading) sectionItems.push(kvObj);
            else out.features_kv.push(kvObj);
            continue;
          }
          if (sectionHeading) sectionItems.push({ key: kv.key, value: kv.value });
          else out.features_kv.push(kv);
          continue;
        }

        const strongInLi = item.html.match(/<strong[^>]*>([\s\S]*?)<\/strong>/i);
        if (strongInLi) {
          const strongKey = stripHtml(strongInLi[1]).replace(/[:.]+$/, '').trim();
          const strongBody = stripHtml(
            item.html.replace(/<strong[^>]*>[\s\S]*?<\/strong>/i, '').replace(/^[\s]*<br\s*\/?>/i, '')
          );
          if (strongBody && strongBody.length > 5) {
            const kvObj = { key: strongKey, value: strongBody };
            if (sectionHeading) sectionItems.push(kvObj);
            else out.features_kv.push(kvObj);
            continue;
          }
        }

        const brParts = item.html.split(/<br\s*\/?>/gi)
          .map(p => stripHtml(p)).filter(p => p.length > 0);

        if (brParts.length > 1) {
          const main = brParts[0];
          const subs = brParts.slice(1);

          if (sectionHeading) {
            sectionItems.push(main);
            subs.forEach(sv => sectionItems.push(sv));
          } else {
            out.features.push(main);
            subs.forEach(sv => {
              const svKV = parseKV(sv);
              if (svKV) out.features_kv.push(svKV);
              else if (sv.length > 3) out.features.push(sv);
            });
          }
          continue;
        }

        if (sectionHeading) sectionItems.push(item.text);
        else out.features.push(item.text);
      }

      if (sectionHeading && sectionItems.length > 0) {
        out.sections.push({ heading: sectionHeading, items: sectionItems });
      } else if (sectionHeading && sectionItems.length === 0) {
        out.description.push(sectionHeading);
      }

      continue;
    }
  }

  // Deduplicación
  out.features = [...new Set(out.features)].filter(f => f.length > 2);

  const kvSeen = new Set();
  out.features_kv = out.features_kv.filter(kv => {
    const k = kv.key.toLowerCase();
    if (kvSeen.has(k)) return false;
    kvSeen.add(k);
    return true;
  });

  out.description = [...new Set(out.description)].filter(d => d.length > 5);
  out.variants = [...new Set(out.variants)].filter(Boolean);

  const compatibilitySeen = new Set();
  out.compatibility = out.compatibility.filter(item => {
    const key = typeof item === 'string'
      ? item.toLowerCase()
      : `${String(item.brand || '').toLowerCase()}::${String(item.models || '').toLowerCase()}`;

    if (!key || compatibilitySeen.has(key)) return false;
    compatibilitySeen.add(key);
    return true;
  });

  const specsSeen = new Set();
  out.table_specs = out.table_specs.filter(spec => {
    const key = [
      String(spec.section || '').toLowerCase(),
      String(spec.name || '').toLowerCase(),
      String(spec.value || '').toLowerCase(),
    ].join('::');

    if (!spec.name || !spec.value || specsSeen.has(key)) return false;
    specsSeen.add(key);
    return true;
  });

  return out;
}

// --- Texto markdown para embedding / chunking ---

function buildFeaturesText(n, productName) {
  const lines = [];

  if (productName) lines.push(`# Características: ${productName}`);
  else lines.push('# Características');

  if (n.description.length > 0) {
    lines.push('');
    lines.push('## Información general');
    n.description.forEach(d => lines.push(d));
  }

  if (n.features.length > 0 || n.features_kv.length > 0) {
    lines.push('');
    lines.push('## Características principales');
    n.features.forEach(f => lines.push(`- ${f}`));
    n.features_kv.forEach(kv => lines.push(`- ${kv.key}: ${kv.value}`));
  }

  n.sections.forEach(sec => {
    lines.push('');
    lines.push(`## ${sec.heading}`);
    sec.items.forEach(item => {
      if (typeof item === 'string') lines.push(`- ${item}`);
      else if (item.key && item.value) lines.push(`- ${item.key}: ${item.value}`);
    });
  });

  if (n.variants.length > 0) {
    lines.push('');
    lines.push('## Variantes / Modelos');
    n.variants.forEach(v => lines.push(`- ${v}`));
  }

  if (n.compatibility.length > 0) {
    lines.push('');
    lines.push('## Compatibilidad / Homologaciones');
    n.compatibility.forEach(c => {
      if (typeof c === 'string') lines.push(`- ${c}`);
      else if (c.brand && c.models) lines.push(`- ${c.brand}: ${c.models}`);
    });
  }

  if (n.kit_contents.length > 0) {
    lines.push('');
    lines.push('## Contenido del kit');
    n.kit_contents.forEach(k => lines.push(`- ${k}`));
  }

  if (n.table_specs.length > 0) {
    lines.push('');
    lines.push('## Datos técnicos adicionales');
    let lastSection = null;

    for (const s of n.table_specs) {
      if (s.section && s.section !== lastSection) {
        lines.push('');
        lines.push(`### ${s.section}`);
        lastSection = s.section;
      }
      lines.push(`- ${s.name}: ${s.value}`);
    }
  }

  return lines.join('\n').trim();
}

// ============================================================
// EJECUCIÓN
// ============================================================

const input = $json;

const caracteristicasHtml = (() => {
  const c = input._raw?.caracteristicas;
  if (Array.isArray(c)) return c.join(' ');
  return String(c || '');
})();

const normalized = extractAndNormalize(caracteristicasHtml);
const featuresText = buildFeaturesText(normalized, input.product_name);

return {
  json: {
    ...input,

    compatibility: normalized.compatibility.length > 0 ? normalized.compatibility : null,
    table_specs:   normalized.table_specs.length   > 0 ? normalized.table_specs   : null,
    variants:      normalized.variants.length       > 0 ? normalized.variants       : null,

    features_text: featuresText || null,
  },
};

// ============================================================
// NODO 2: Especificaciones técnicas
// Responsabilidad: parsear la tabla <table> de especificaciones.
// Soporta encabezados de sección con <td colspan="2"><strong>.
//
// Salida: specs[], specs_text (markdown para RAG)
// Cada spec: { name, value, section?, items? }
// ============================================================

// --- Utilidades ---

function decodeHtml(text) {
  if (!text) return '';
  return String(text)
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&lt;/gi, '<')
    .replace(/&gt;/gi, '>')
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, "'")
    .replace(/&apos;/gi, "'")
    .replace(/&ndash;/gi, '–')
    .replace(/&mdash;/gi, '—')
    .replace(/&bull;/gi, '•')
    .replace(/&middot;/gi, '·')
    .replace(/&hellip;/gi, '…')
    .replace(/&deg;/gi, '°')
    .replace(/&times;/gi, '×')
    .replace(/&#x([0-9a-f]+);/gi, (_, h) => String.fromCodePoint(parseInt(h, 16)))
    .replace(/&#(\d+);/g, (_, d) => String.fromCodePoint(parseInt(d, 10)));
}

function cleanText(text) {
  return decodeHtml(text)
    .replace(/\r/g, '')
    .replace(/[ \t]+/g, ' ')
    .replace(/ *\n */g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function stripAllTags(html) {
  return String(html || '')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/li>/gi, '\n')
    .replace(/<li[^>]*>/gi, '')
    .replace(/<\/p>/gi, '\n')
    .replace(/<p[^>]*>/gi, '\n')
    .replace(/<\/div>/gi, '\n')
    .replace(/<div[^>]*>/gi, '\n')
    .replace(/<\/tr>/gi, '\n')
    .replace(/<[^>]+>/g, '');
}

function stripHtml(html) {
  return cleanText(stripAllTags(html));
}

function stripHtmlAsValue(html) {
  const multiline = stripHtml(html);
  if (!multiline) return '';
  return multiline.split('\n').map(s => s.trim()).filter(Boolean).join(' | ');
}

function extractListItems(ulHtml) {
  const items = [];
  const liRegex = /<li[^>]*>([\s\S]*?)<\/li>/gi;
  let m;
  while ((m = liRegex.exec(ulHtml)) !== null) {
    const text = stripHtml(m[1]);
    if (text) items.push(text);
  }
  return items;
}

// --- Filtros de ruido ---

const EDITORIAL_NOISE = [
  /^borrar$/i,
  /^a[ñn]adir!+$/i,
  /^agregar!+$/i,
  /^(todo|tbd|pendiente)!*$/i,
  /^\*+\s*(en\s+)?(curso|proceso|progreso)/i,
  /^\(\*?\s*en\s+(curso|proceso|progreso)\s*\)$/i,
];

function isEditorialNoise(text) {
  const t = (text || '').trim();
  if (!t) return true;
  return EDITORIAL_NOISE.some(p => p.test(t));
}

const CTA_PATTERNS = [
  /solicitar\s+bajo\s+demanda/i,
  /solicitud\s+bajo\s+demanda/i,
  /para\s+obtener\s+m[aá]s\s+aplicaciones/i,
  /visite\s+www\./i,
  /consulte\s+(la\s+)?información\s+de\s+pedidos/i,
  /para\s+m[aá]s\s+apps/i,
  /contáctenos/i,
];

function isCTA(text) {
  const t = stripHtml(text);
  if (!t || t.length < 10) return false;
  return CTA_PATTERNS.some(p => p.test(t));
}

// --- Parser de tabla ---

function parseSectionRow(rowHtml) {
  const cellMatches = [...rowHtml.matchAll(/<(t[dh])([^>]*)>([\s\S]*?)<\/\1>/gi)];
  if (cellMatches.length !== 1) return null;
  const attrs = cellMatches[0][2] || '';
  const inner = cellMatches[0][3];
  const hasColspan = /colspan\s*=\s*["']?\s*[2-9]/i.test(attrs);
  if (!hasColspan) return null;
  const hasStrong = /<strong[^>]*>/i.test(inner);
  const text = stripHtml(inner);
  return { text, isStrong: hasStrong };
}

function parseSpecsTable(html) {
  const source = String(html || '');
  if (!source.trim()) return [];

  const rows = [...source.matchAll(/<tr[^>]*>([\s\S]*?)<\/tr>/gi)];
  const specs = [];
  let currentSection = null;

  for (const rowMatch of rows) {
    const rowHtml = rowMatch[1];

    // Fila-sección: <td colspan="2"><strong>Título</strong></td>
    const section = parseSectionRow(rowHtml);
    if (section) {
      if (section.isStrong && section.text &&
          !isEditorialNoise(section.text) && !isCTA(section.text)) {
        currentSection = section.text;
      }
      // colspan sin <strong> = nota/footer, se descarta para RAG
      continue;
    }

    // Fila de datos estándar
    const cells = [...rowHtml.matchAll(/<t[dh][^>]*>([\s\S]*?)<\/t[dh]>/gi)]
      .map(m => ({ html: m[1], text: stripHtml(m[1]), valueText: stripHtmlAsValue(m[1]) }));

    if (cells.length < 2) continue;
    if (cells.every(c => c.text.length === 0)) continue;
    if (cells.every(c => isEditorialNoise(c.text))) continue;

    const name = cells[0].text;
    const valueCellHtml = cells[1].html;

    let value;
    let items = null;
    if (/<li/i.test(valueCellHtml)) {
      items = extractListItems(valueCellHtml);
      value = items.join(' | ');
    } else {
      value = cells.slice(1).map(c => c.valueText).filter(Boolean).join(' | ').trim();
    }

    if (!name || !value) continue;
    if (isEditorialNoise(name) || isEditorialNoise(value)) continue;
    if (isCTA(value)) continue;

    const spec = { name, value };
    if (currentSection) spec.section = currentSection;
    if (items) spec.items = items;
    specs.push(spec);
  }

  return specs;
}

// --- Texto markdown para el RAG ---
// Genera un bloque indexable con jerarquía sección → spec.

function buildSpecsText(specs, productName) {
  if (specs.length === 0) return '';

  const lines = [];
  if (productName) lines.push(`# Especificaciones técnicas: ${productName}`);
  else lines.push('# Especificaciones técnicas');

  let lastSection = null;
  for (const s of specs) {
    if (s.section && s.section !== lastSection) {
      lines.push('');
      lines.push(`## ${s.section}`);
      lastSection = s.section;
    }
    if (s.value && s.value !== s.name) lines.push(`- ${s.name}: ${s.value}`);
    else lines.push(`- ${s.name}`);
  }

  return lines.join('\n').trim();
}

// --- Parser de lista <ul>/<li> (paneles sin <table>) ---
// Algunas páginas presentan las especificaciones como <ul><li> en vez de
// <table>. Cada <li> es una spec: "Nombre: valor", "Nombre:<br>sub1<br>sub2",
// o un enunciado suelto sin ":".

function parseSpecsList(html) {
  const specs = [];
  for (const raw of extractListItems(html)) {
    const lines = raw
      .split('\n')
      .map(s => s.replace(/^[–—\-•·]\s*/, '').trim())
      .filter(Boolean);
    if (lines.length === 0) continue;

    const head = lines[0];
    const subs = lines.slice(1);
    const kv = head.match(/^([^:]{1,80}):\s*(.+)$/);

    let name, value;
    let items = null;

    if (kv) {
      name = kv[1].trim();
      const headVal = kv[2].trim();
      if (subs.length) items = subs;
      value = [headVal, ...subs].filter(Boolean).join(' | ');
    } else if (subs.length) {
      name = head.replace(/:\s*$/, '').trim();
      items = subs;
      value = subs.join(' | ');
    } else {
      name = head;
      value = head;
    }

    if (!name) continue;
    if (isEditorialNoise(name) || isEditorialNoise(value) || isCTA(value)) continue;

    const spec = { name, value };
    if (items) spec.items = items;
    specs.push(spec);
  }
  return specs;
}

