const input = $json;
const specsHtml = String(input._raw?.especificaciones_html || '');
const specs = /<table/i.test(specsHtml)
  ? parseSpecsTable(specsHtml)
  : parseSpecsList(specsHtml);
const specsText = buildSpecsText(specs, input.product_name);

return {
  json: {
    ...input,

    specs:      specs.length > 0 ? specs      : null,
    specs_text: specsText        ? specsText  : null,
  },
};

function htmlToText(html) {
  if (!html) return '';
  let t = String(html);
  t = t.replace(/<a\s[^>]*>\s*<img[\s\S]*?<\/a>/gi, '');
  t = t.replace(/<noscript[\s\S]*?<\/noscript>/gi, '');
  t = t.replace(/<img[^>]*>/gi, '');
  t = t.replace(/<a\s[^>]*>([\s\S]*?)<\/a>/gi, '$1');
  t = t.replace(/<br\s*\/?>/gi, '\n');
  t = t.replace(/<li[^>]*>/gi, '• ');
  t = t.replace(/<\/li>/gi, '\n');
  t = t.replace(/<p[^>]*>/gi, '\n').replace(/<\/p>/gi, '\n');
  t = t.replace(/<\/?[a-z][^>]*>/gi, '');
  t = t.replace(/&nbsp;/g, ' ')
       .replace(/&amp;/g, '&')
       .replace(/&lt;/g, '<')
       .replace(/&gt;/g, '>')
       .replace(/&quot;/g, '"')
       .replace(/&#39;/g, "'");
  t = t.replace(/[ \t]+/g, ' ').replace(/\n\s*\n+/g, '\n');
  return t.trim();
}

function normalizeForHash(text) {
  return String(text || '')
    .toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9\s]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function simpleHash(text) {
  let hash = 0;
  const str = normalizeForHash(text);
  for (let i = 0; i < str.length; i++) {
    hash = ((hash << 5) - hash) + str.charCodeAt(i);
    hash |= 0;
  }
  return Math.abs(hash);
}

function isRichSoftwareText(text) {
  const clean = String(text || '').replace(/\s+/g, ' ').trim();
  if (!clean) return false;
  const words = clean.split(/\s+/).length;
  const hasSignals = /(gesti[oó]n|monitor|vpn|router|gateway|dispositivo|nube|cloud|alerta|configura|administr)/i.test(clean);
  return words >= 18 || (words >= 10 && hasSignals);
}

function detectarNombre(fragmentos) {
  // El nombre del software es una línea-título corta. Con el selector .product > *
  // un fragmento puede ser un bloque multilínea (div/ul); tomamos su primera línea.
  const firstLine = (f) => String(f || '').split('\n').map(s => s.trim()).filter(Boolean)[0] || '';
  for (const f of fragmentos) {
    const line = firstLine(f);
    if (line.length > 0 && line.length < 80 && !line.endsWith(':')) return line;
  }
  return firstLine(fragmentos[0]) || 'Desconocido';
}

function extractSoftwareAttributes(text) {
  const attrs = new Set(['cloud_management']);
  if (/\b(vpn|openvpn|ipsec|wireguard)\b/i.test(text)) attrs.add('vpn');
  if (/\bsd-?wan\b/i.test(text)) attrs.add('sdwan');
  if (/\bdocker\b/i.test(text)) attrs.add('docker');
  if (/\bmqtt\b/i.test(text)) attrs.add('mqtt');
  if (/\bmodbus\b/i.test(text)) attrs.add('modbus');
  return Array.from(attrs);
}

const items = $input.all().map(i => i.json);
const softwareGroups = {};

const precomputados = items.map(data => {
  const arr = data._raw.software_gestion;
  if (!Array.isArray(arr) || arr.length === 0) return { data, softwareId: null };

  const limpios = arr.map(htmlToText).filter(f => f && f.length > 0);
  if (limpios.length === 0) return { data, softwareId: null };

  const texto = limpios.join('\n');
  if (!isRichSoftwareText(texto)) return { data, softwareId: null };

  const nombre = detectarNombre(limpios);
  const brand = data.brand || 'sin-marca';

  // Hashear solo el cuerpo (sin el primer fragmento/nombre) para que
  // variaciones menores en el título no generen software_id distintos
  const fragmentosCuerpo = limpios.length > 1 ? limpios.slice(1) : limpios;
  const cuerpo = fragmentosCuerpo.join('\n');
  const softwareId = simpleHash(brand + '|' + normalizeForHash(cuerpo));

  if (!softwareGroups[softwareId]) {
    softwareGroups[softwareId] = {
      canonical_product_id: data.id,
      nombre,
      texto,
      fragmentos: limpios.length,
    };
  }

  return { data, softwareId, nombre, fragmentos: limpios.length, caracteres: texto.length };
});

const resultados = [];
for (const p of precomputados) {
  const { data, softwareId } = p;

  const output = {
    ...data,
    software_id: null,
    software_nombre: null,
    software_texto: null,
    software_fragmentos: 0,
    software_caracteres: 0,
    software_attributes: [],
    is_software_canonical: false,
  };
  delete output._raw;

  if (softwareId) {
    const group = softwareGroups[softwareId];
    const isCanonical = group.canonical_product_id === data.id;

    output.software_id = softwareId;
    output.software_nombre = p.nombre;
    output.software_fragmentos = p.fragmentos;
    output.software_caracteres = p.caracteres;

    if (isCanonical) {
      output.is_software_canonical = true;
      output.software_texto = group.texto;
      output.software_attributes = extractSoftwareAttributes(group.texto);
    }
  }

  resultados.push({ json: output });
}

return resultados;

