function decodeHtml(text) {
  if (!text) return '';
  return String(text)
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&lt;/gi, '<')
    .replace(/&gt;/gi, '>')
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, "'")
    .replace(/&apos;/gi, "'");
}

function cleanText(text) {
  return decodeHtml(text)
    .replace(/\r/g, '')
    .replace(/[ \t]+/g, ' ')
    .replace(/ *\n */g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function getSlugProduct(url) {
  try {
    const partes = url.split('/').filter(Boolean);
    const index = partes.indexOf('producto');
    return index !== -1 && partes[index + 1] ? partes[index + 1] : null;
  } catch {
    return null;
  }
}

