function slugify(value) {
  return String(value || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/&/g, ' y ')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .replace(/-{2,}/g, '-');
}

// Categorías genéricas que aparecen al inicio de un name pero NO son marca.
// Si el catálogo crece y entra un producto cuya primera palabra/token del name
// sea una categoría nueva, agregarla aquí. Lista en lowercase.
const GENERIC_FIRST_WORDS = new Set([
  'antena',
  'cable',
  'kit',
  'módulo',
  'modulo',
  'modem',
  'módem',
  'router',
  'gateway',
  'switch',
  'transceptor',
  'adaptador',
  'fuente',
  'accesorio',
  'conector',
  'sensor',
  'panel',
  'soporte',
  'rack'
]);

function decodeHtmlEntities(value) {
  return String(value || '')
    .replace(/&#8211;/g, '–')
    .replace(/&#8212;/g, '—')
    .replace(/&amp;/g, '&')
    .replace(/&gt;/g, '>')
    .replace(/&lt;/g, '<')
    .trim();
}

function getAttributeOptionValue(option) {
  if (option == null) return null;

  if (typeof option === 'string') {
    const value = option.trim();
    return value || null;
  }

  const value =
    option.name ??
    option.option ??
    option.value ??
    option.label ??
    null;

  return value == null ? null : String(value).trim() || null;
}

function escapeRegExp(value) {
  return String(value).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function normalizeAlias(value) {
  return String(value || '')
    .replace(/[_\-–—/]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function addUniqueAlias(aliases, seen, value, sourceValues = []) {
  if (value == null) return;

  const str = String(value).trim();
  if (!str) return;

  const normalized = normalizeAlias(str);
  if (!normalized) return;

  // Evita guardar aliases que son iguales a columnas base:
  // id, slug, name, brand, model.
  const isDuplicateOfSource = sourceValues.some(source => {
    if (source == null) return false;

    const sourceStr = String(source).trim();
    if (!sourceStr) return false;

    return (
      str.toLowerCase() === sourceStr.toLowerCase() ||
      normalized.toLowerCase() === normalizeAlias(sourceStr).toLowerCase()
    );
  });

  if (isDuplicateOfSource) return;

  const key = normalized.toLowerCase();
  if (seen.has(key)) return;

  seen.add(key);
  aliases.push(normalized);
}

function extractBrandModel(product) {
  const name = decodeHtmlEntities(product.name || '');

  // 1) Fuente primaria: attribute `fabricante` desde WooCommerce.
  const brandAttr = (product.attributes || []).find(a =>
    /fabricante/i.test(a.taxonomy || a.name || '')
  );

  let brand = getAttributeOptionValue(brandAttr?.options?.[0]);
  let brandSource = brand ? 'attribute' : null;

  // 2) Fallback heurístico filtrado: SOLO si no hay attribute.
  //    Reglas conservadoras:
  //      a. El name puede venir separado por espacios o guiones.
  //         Ej:
  //           "3onedata Gateway GW1114"
  //           "3onedata-Gateway-GW1114"
  //      b. El primer token NO debe ser categoría genérica.
  //         Ej:
  //           "Antena Magnética..." -> "Antena" no es marca.
  //           "Gateway GW1114..."   -> "Gateway" no es marca.
  //      c. El primer token debe medir >= 2 caracteres.
  if (!brand && name) {
    const firstToken = name.trim().split(/[\s\-–—_/]+/)[0];

    if (
      firstToken.length >= 2 &&
      !GENERIC_FIRST_WORDS.has(firstToken.toLowerCase())
    ) {
      brand = firstToken;
      brandSource = 'heuristic';
    }
  }

  // 3) Model solo se extrae si tenemos brand confiable
  //    Y el name empieza con esa brand.
  //    Remueve separadores después de la marca:
  //      "3onedata-Gateway-GW1114" -> "Gateway-GW1114"
  //      "3onedata Gateway GW1114" -> "Gateway GW1114"
  let model = null;

  if (brand) {
    const brandPattern = new RegExp(
      `^${escapeRegExp(brand)}[\\s\\-–—_/]*`,
      'i'
    );

    if (brandPattern.test(name)) {
      model = name.replace(brandPattern, '').trim() || null;
    }
  }

  return { name, brand, model, brandSource };
}

function buildSearchAliases({ id, slug, name, brand, model }) {
  const seen = new Set();
  const aliases = [];

  const sourceValues = [
    id,
    slug,
    name,
    brand,
    model
  ];

  // No guardar directamente id, slug, name, brand ni model.
  // Esos ya entran al search_text por columnas del trigger.
  //
  // search_aliases queda solo para variantes útiles que NO existen
  // literalmente en las columnas base.

  const readableSlug = normalizeAlias(slug);
  const readableName = normalizeAlias(name);
  const readableModel = normalizeAlias(model);

  addUniqueAlias(aliases, seen, readableSlug, sourceValues);
  addUniqueAlias(aliases, seen, readableName, sourceValues);
  addUniqueAlias(aliases, seen, readableModel, sourceValues);

  // Variante brand + model con espacios.
  // Útil cuando el name viene con guiones:
  //   name:  "3onedata-Gateway-GW1114"
  //   alias: "3onedata Gateway GW1114"
  if (brand && model) {
    addUniqueAlias(
      aliases,
      seen,
      normalizeAlias(`${brand} ${model}`),
      sourceValues
    );
  }

  return aliases;
}

// Catálogo completo — corrió una sola vez, tiene todos los productos
const catalog = $('Get Products Catalog').first().json;

// Todos los items de identificación — uno por producto
const products = $('Identificación del producto').all();

return products.map(item => {
  const p = item.json;

  const catalogKey = slugify(p.slug);
  const entry = catalog[catalogKey] ?? null;

  const extracted = entry
    ? extractBrandModel(entry)
    : {
        name: null,
        brand: null,
        model: null,
        brandSource: null
      };

  return {
    json: {
      // ── de "Identificar producto" ──
      slug:                   p.slug,
      source_url:             p.source_url,
      description:            p.description,
      productos_recomendados: p.productos_recomendados,
      _raw:                   p._raw,

      // ── de "get catalog product" ──
      id:           entry?.id          ?? null,
      name:         extracted.name,
      brand:        extracted.brand,
      model:        extracted.model,
      brand_source: extracted.brandSource,
      category_id:  entry?.category_id ?? null,
      is_new:     entry?.is_new    ?? false,
      attributes:   entry?.attributes  ?? [],

      search_aliases: entry
        ? buildSearchAliases({
            id:    entry.id,
            slug:  entry.slug,
            name:  extracted.name,
            brand: extracted.brand,
            model: extracted.model
          })
        : []
    }
  };
});

const seen = new Set();
const uniqueItems = [];

for (const item of $input.all()) {
  const categoryId = item.json.category_id;
  const attributes = item.json.attributes;

  for (const attribute of attributes) {
    const attributeId = attribute.attribute_id

    if (categoryId == null || attributeId == null) continue;

    const key = `${categoryId}:${attributeId}`;

    if (!seen.has(key)) {
      seen.add(key);

      uniqueItems.push({
        json: {
          category_id: categoryId,
          attribute_id: attributeId,
        },
      });
    }

  }

}

return uniqueItems;

return $input.all().filter(item =>
  item.json.is_software_canonical === true
);

const allowedFields = [
  'id',
  'slug',
  'name',
  'brand',
  'model',
  'category_id',
  'source_url',
  'description',
  'attributes',
  'is_new',
  'search_aliases',
  'software_id',
];

return $input.all().map(item => {
  const output = {};

  for (const field of allowedFields) {
    if (item.json[field] !== undefined) {
      output[field] = item.json[field];
    }
  }

  return {
    json: output,
  };
});

