const allowedFields = [
  'id',
  'specs',
  'table_specs',
  'variants',
  'compatibility',
  'specs_text',
  'features_text',
];

const fingerprintFields = [
  'specs',
  'table_specs',
  'variants',
  'compatibility',
  'specs_text',
  'features_text',
];

function stableStringify(value) {
  if (value === undefined || value === null) return '';

  if (typeof value !== 'object') {
    return String(value);
  }

  if (Array.isArray(value)) {
    return JSON.stringify(value.map(v => normalizeObject(v)));
  }

  return JSON.stringify(normalizeObject(value));
}

function normalizeObject(value) {
  if (value === null || typeof value !== 'object') return value;

  if (Array.isArray(value)) {
    return value.map(normalizeObject);
  }

  return Object.keys(value)
    .sort()
    .reduce((acc, key) => {
      acc[key] = normalizeObject(value[key]);
      return acc;
    }, {});
}

return $input.all().map(item => {
  const output = {};

  for (const field of allowedFields) {
    if (item.json[field] !== undefined) {
      output[field === 'id' ? 'product_id' : field] = item.json[field];
    }
  }

  output.specs_fingerprint = fingerprintFields
    .map(field => `${field}:${stableStringify(item.json[field])}`)
    .join('|');

  return {
    json: output,
  };
});

const MAX_TOKENS = 500;
const TARGET_TOKENS = 430;
const MIN_TOKENS = 30;
const STRICT_VARIANTS = true;
const INCLUDE_DENORMALIZED_COLUMNS = false;
const INCLUDE_LOGICAL_KEY = true;
const OUTPUT_MODE = 'chunks'; // 'chunks' | 'diagnostics'

function tokenCount(value) {
  const text = String(value || '').trim();
  if (!text) return 0;
  return text.split(/\s+/).filter(Boolean).length;
}

function cleanText(value) {
  return String(value ?? '')
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n')
    .replace(/[ \t]+\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function words(value) {
  return cleanText(value).split(/\s+/).filter(Boolean);
}

function truncateWords(value, maxWords) {
  const ws = words(value);
  if (ws.length <= maxWords) return cleanText(value);
  return ws.slice(0, maxWords).join(' ') + '...';
}

function toArray(value) {
  if (Array.isArray(value)) return value;
  if (value === null || value === undefined || value === '') return [];
  return [value];
}

function parseMaybeJson(value) {
  if (typeof value !== 'string') return value;
  const text = value.trim();
  if (!text) return value;
  if (!text.startsWith('{') && !text.startsWith('[')) return value;
  try { return JSON.parse(text); } catch (_) { return value; }
}

function collectProducts(inputItems) {
  const products = [];

  function add(candidate) {
    candidate = parseMaybeJson(candidate);
    if (Array.isArray(candidate)) {
      for (const row of candidate) add(row);
      return;
    }
    if (!candidate || typeof candidate !== 'object') return;

    if (Array.isArray(candidate.data)) return add(candidate.data);
    if (Array.isArray(candidate.products)) return add(candidate.products);
    if (Array.isArray(candidate.items)) return add(candidate.items);
    if (typeof candidate.data === 'string') return add(candidate.data);
    if (typeof candidate.body === 'string') return add(candidate.body);
    if (typeof candidate.text === 'string') return add(candidate.text);
    if (typeof candidate.output === 'string') return add(candidate.output);

    if (candidate.json && typeof candidate.json === 'object') return add(candidate.json);
    if (candidate.id !== undefined && candidate.name) products.push(candidate);
  }

  for (const item of inputItems) add(item.json ?? item);
  return products;
}

function optionNames(attribute) {
  return toArray(attribute?.options)
    .map(o => cleanText(o?.name ?? o))
    .filter(Boolean);
}

function attributesToPairs(attributes) {
  return toArray(attributes)
    .map(a => ({
      name: cleanText(a?.name),
      taxonomy: cleanText(a?.taxonomy),
      values: optionNames(a),
    }))
    .filter(a => a.name && a.values.length);
}

function attributesObject(attributes) {
  const obj = {};
  for (const a of attributesToPairs(attributes)) obj[a.name] = a.values.length === 1 ? a.values[0] : a.values;
  return obj;
}

function isAffirmative(value) {
  return /^(si|sí|yes|true)$/i.test(cleanText(value));
}

function keyAttributes(attributes) {
  const preferred = [
    'Fabricante', 'Fabricantetrans', 'Uso', 'Red celular', 'Red transmisor', 'WiFi',
    'WAN', 'LAN', 'Puertos seriales', 'I/O', 'SDWAN', 'Software de gestión',
    'Software transmisor', 'Tipo de Accesorio', 'Tipo de antena', 'dBI', '4G LTE',
    '5G', '2G-3G', 'Modo', 'Tipo de Conector', 'Distacia antena', 'Tipo de dispositivo',
    'Red', 'Capacidad', 'Factor de forma', 'Distancia SFP'
  ];
  const pairs = attributesToPairs(attributes);
  const score = (name) => {
    const i = preferred.findIndex(p => p.toLowerCase() === name.toLowerCase());
    return i === -1 ? 999 : i;
  };
  return pairs
    .sort((a, b) => score(a.name) - score(b.name) || a.name.localeCompare(b.name))
    .map(a => `${a.name}: ${a.values.join(', ')}`);
}

function buildProductMetadata(p) {
  return {
    source: 'product',
    product_id: p.id ?? null,
    product_name: p.name ?? null,
    slug: p.slug ?? null,
    brand: p.brand ?? null,
    model: p.model ?? null,
    brand_source: p.brand_source ?? null,
    category_id: p.category_id ?? null,
    source_url: p.source_url ?? null,
    is_new: Boolean(p.is_new),
    recommended_slugs: toArray(p.productos_recomendados),
    search_aliases: toArray(p.search_aliases),
    attributes: attributesObject(p.attributes),
    software_id: p.software_id ?? null,
    software_name: p.software_nombre ?? null,
  };
}

function buildSoftwareMetadata(p) {
  return {
    source: 'software',
    software_id: p.software_id ?? null,
    software_name: p.software_nombre ?? null,
    software_attributes: toArray(p.software_attributes),
    canonical_from_product_id: p.id ?? null,
    canonical_from_product_name: p.name ?? null,
    brand: p.brand ?? null,
    source_url: p.source_url ?? null,
  };
}

function normalizeSectionName(value) {
  const text = cleanText(value);
  return text || null;
}

function logicalKey(sourceType, productId, softwareId, chunkType, sectionName) {
  return `${sourceType}:${productId ?? softwareId ?? 'null'}:${chunkType}:${sectionName ?? ''}`;
}

function rowBase(p, chunkType, sectionName, content, metadata, sourceType = 'product') {
  const isSoftware = sourceType === 'software';
  const productId = isSoftware ? null : (p.id ?? null);
  const softwareId = isSoftware ? (p.software_id ?? null) : null;
  const sec = normalizeSectionName(sectionName);

  const row = {
    product_id: productId,
    software_id: softwareId,
    source_type: sourceType,
    chunk_type: chunkType,
    section_name: sec,
    content: cleanText(content),
    metadata,
    embedding: null,
  };

  if (INCLUDE_DENORMALIZED_COLUMNS) {
    Object.assign(row, {
      product_name: isSoftware ? null : (p.name ?? null),
      software_name: p.software_nombre ?? null,
      brand: p.brand ?? null,
      model: p.model ?? null,
      slug: p.slug ?? null,
      category_id: isSoftware ? null : (p.category_id ?? null),
      source_url: p.source_url ?? null,
    });
  }

  if (INCLUDE_LOGICAL_KEY) {
    row.source_key = logicalKey(sourceType, productId, softwareId, chunkType, sec);
  }

  return row;
}

function withProductPrefix(p, body, header) {
  const lines = [`[${cleanText(p.name) || 'Producto'}]`];
  if (header) lines.push(`## ${cleanText(header)}`);
  lines.push(cleanText(body));
  return cleanText(lines.join('\n'));
}

function withSoftwarePrefix(p, body) {
  const name = cleanText(p.software_nombre) || 'Software';
  return cleanText(`[${name}]\n## Software\n${cleanText(body)}`);
}

function splitOversizeContent(p, chunkType, sectionName, body, metadata, sourceType = 'product', header = sectionName) {
  const prefixBuilder = sourceType === 'software'
    ? (partBody) => withSoftwarePrefix(p, partBody)
    : (partBody, partHeader) => withProductPrefix(p, partBody, partHeader);

  const initial = prefixBuilder(body, header);
  if (tokenCount(initial) <= MAX_TOKENS) {
    if (tokenCount(initial) < MIN_TOKENS && chunkType !== 'overview' && chunkType !== 'software') return [];
    return [rowBase(p, chunkType, sectionName, initial, metadata, sourceType)];
  }

  const lines = cleanText(body).split('\n').filter(line => cleanText(line));
  const chunks = [];
  let current = [];
  let part = 1;

  function flush() {
    if (!current.length) return;
    const partBody = current.join('\n');
    const sec = sectionName ? `${sectionName} parte ${part}` : `parte ${part}`;
    const h = header ? `${header} parte ${part}` : sec;
    const content = prefixBuilder(partBody, h);
    if (tokenCount(content) >= MIN_TOKENS || chunkType === 'overview') {
      chunks.push(rowBase(p, chunkType, sec, content, metadata, sourceType));
      part += 1;
    }
    current = [];
  }

  for (const line of lines) {
    const candidate = [...current, line].join('\n');
    const candidateContent = prefixBuilder(candidate, header ? `${header} parte ${part}` : `parte ${part}`);

    if (tokenCount(prefixBuilder(line, header)) > MAX_TOKENS) {
      flush();
      const ws = words(line);
      let buf = [];
      for (const w of ws) {
        const cand = [...buf, w].join(' ');
        const sec = sectionName ? `${sectionName} parte ${part}` : `parte ${part}`;
        const h = header ? `${header} parte ${part}` : sec;
        if (tokenCount(prefixBuilder(cand, h)) > TARGET_TOKENS && buf.length) {
          const partBody = buf.join(' ');
          const content = prefixBuilder(partBody, h);
          if (tokenCount(content) >= MIN_TOKENS) chunks.push(rowBase(p, chunkType, sec, content, metadata, sourceType));
          part += 1;
          buf = [w];
        } else {
          buf.push(w);
        }
      }
      if (buf.length) {
        const sec = sectionName ? `${sectionName} parte ${part}` : `parte ${part}`;
        const h = header ? `${header} parte ${part}` : sec;
        const content = prefixBuilder(buf.join(' '), h);
        if (tokenCount(content) >= MIN_TOKENS) chunks.push(rowBase(p, chunkType, sec, content, metadata, sourceType));
        part += 1;
      }
      continue;
    }

    if (current.length && tokenCount(candidateContent) > TARGET_TOKENS) flush();
    current.push(line);
  }
  flush();
  return chunks.filter(r => tokenCount(r.content) <= MAX_TOKENS);
}

function addChunk(rows, p, chunkType, sectionName, body, metadata, sourceType = 'product', header = sectionName) {
  const cleanBody = cleanText(body);
  if (!cleanBody) return;
  rows.push(...splitOversizeContent(p, chunkType, sectionName, cleanBody, metadata, sourceType, header));
}

function normalizedWordSet(text) {
  return new Set(cleanText(text).toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9ñ\s]/gi, ' ')
    .split(/\s+/)
    .filter(w => w.length > 3));
}

function overlapRatio(a, b) {
  const A = normalizedWordSet(a);
  const B = normalizedWordSet(b);
  if (!A.size || !B.size) return 0;
  let inter = 0;
  for (const w of A) if (B.has(w)) inter += 1;
  return inter / Math.min(A.size, B.size);
}

function buildOverviewBody(p) {
  const name = cleanText(p.name);
  const brand = cleanText(p.brand);
  const model = cleanText(p.model);
  const desc = truncateWords(p.description, 42);
  const attrs = keyAttributes(p.attributes);

  const identity = [
    name,
    brand ? `marca ${brand}` : '',
    model && model !== name ? `modelo ${model}` : '',
  ].filter(Boolean).join(', ');

  let body = `${identity}.`;
  if (desc) body += ` ${desc}`;
  if (attrs.length) body += ` Atributos clave: ${attrs.slice(0, 10).join('; ')}.`;

  while (tokenCount(body) > 185 && attrs.length > 3) {
    attrs.pop();
    body = `${identity}.`;
    if (desc) body += ` ${desc}`;
    body += ` Atributos clave: ${attrs.join('; ')}.`;
  }
  return cleanText(body);
}

function buildCompatibilityText(value) {
  const arr = toArray(value).filter(v => v !== null && v !== undefined && cleanText(v));
  if (!arr.length) return '';
  const lines = ['## Compatibilidad / Homologaciones'];
  for (const item of arr) {
    if (typeof item === 'string') {
      lines.push(`- ${cleanText(item)}`);
    } else if (typeof item === 'object') {
      const brand = cleanText(item.brand ?? item.fabricante ?? item.marca ?? item.name);
      const models = cleanText(item.models ?? item.modelos ?? item.modelo ?? item.value ?? item.descripcion);
      if (brand && models) lines.push(`- ${brand}: ${models}`);
      else if (brand) lines.push(`- ${brand}`);
      else if (models) lines.push(`- ${models}`);
      else lines.push(`- ${cleanText(JSON.stringify(item))}`);
    }
  }
  return cleanText(lines.join('\n'));
}

function extractModelCodes(text) {
  const t = cleanText(text);
  const patterns = [
    /\b[A-Z]{2,}[A-Z0-9]*[-_][A-Z0-9][A-Z0-9-]*\b/g,
    /\b[A-Z]{1,8}\d{2,}[A-Z0-9-]*\b/g,
    /\b\d+[A-Z]{1,4}[A-Z0-9-]*\b/g,
  ];
  const found = new Set();
  for (const re of patterns) {
    for (const match of t.matchAll(re)) found.add(match[0].toUpperCase());
  }
  return [...found];
}

function productModelCodes(p) {
  return new Set([
    ...extractModelCodes(p?.model || ''),
    ...extractModelCodes(p?.name || ''),
  ]);
}

function isRelevantVariantItem(item, p) {
  const t = cleanText(typeof item === 'string' ? item : JSON.stringify(item));
  if (!t) return false;

  const productCodes = productModelCodes(p);
  const codes = extractModelCodes(t);

  if (codes.some(code => !productCodes.has(code))) return true;

  if (/\b(LTE-A|LTE-M|NB-IoT|CAT\s?\d+|PoE\+?|SFP\+?)\b/i.test(t)) return true;

  if (/\b(viene en|incluye|contiene|ofrece)\s*\d+\s*(modelos|productos|referencias)\b/i.test(t)) return true;
  if (/\b(familia|serie)\b.*\b(contiene|incluye)\s*\d+\s*(productos|modelos|referencias)\b/i.test(t)) return true;

  if (/^\s*(modelo|modelos|versi[oó]n|variante|variantes)\b/i.test(t)) return true;

  return false;
}

function buildVariantsText(value, p) {
  const arr = toArray(value).filter(v => v !== null && v !== undefined && cleanText(v));
  if (!arr.length) return '';

  const filtered = STRICT_VARIANTS
    ? arr.filter(v => isRelevantVariantItem(v, p))
    : arr;

  if (!filtered.length) return '';
  const lines = ['## Variantes / Modelos'];
  for (const item of filtered) {
    if (typeof item === 'string') lines.push(`- ${cleanText(item)}`);
    else if (typeof item === 'object') {
      const name = cleanText(item.name ?? item.modelo ?? item.model ?? item.variant ?? item.variante);
      const desc = cleanText(item.description ?? item.descripcion ?? item.value ?? item.diferencias);
      if (name && desc) lines.push(`- ${name}: ${desc}`);
      else if (name) lines.push(`- ${name}`);
      else if (desc) lines.push(`- ${desc}`);
      else lines.push(`- ${cleanText(JSON.stringify(item))}`);
    }
  }
  return cleanText(lines.join('\n'));
}

function sectionTitleMatches(title, patterns) {
  const t = cleanText(title).toLowerCase();
  return patterns.some(p => p.test(t));
}

function splitH2Sections(markdown) {
  const text = cleanText(markdown);
  if (!text) return [];
  const lines = text.split('\n');
  const sections = [];
  let title = null;
  let buf = [];

  function push() {
    const content = cleanText(buf.join('\n'));
    if (content) sections.push({ title: title || 'General', content });
    buf = [];
  }

  for (const line of lines) {
    const h2 = line.match(/^##\s+(.+)\s*$/);
    const h1 = line.match(/^#\s+(.+)\s*$/);
    if (h2) {
      push();
      title = cleanText(h2[1]);
      buf.push(`## ${title}`);
    } else if (h1) {
      if (title) buf.push(line);
    } else {
      buf.push(line);
    }
  }
  push();
  return sections;
}

function extractH2Section(markdown, patterns) {
  const sections = splitH2Sections(markdown);
  const found = sections.find(s => sectionTitleMatches(s.title, patterns));
  return found ? cleanText(found.content) : '';
}

function removeH2Sections(markdown, patternGroups) {
  const active = patternGroups.filter(Boolean);
  if (!active.length) return cleanText(markdown);
  const sections = splitH2Sections(markdown);
  const kept = sections.filter(s => !active.some(group => sectionTitleMatches(s.title, group)));
  if (!kept.length) return '';
  return cleanText(['# Características', ...kept.map(s => s.content)].join('\n\n'));
}

function mergeSmallSections(sections, minTokens = 100, maxTokens = 500) {
  const out = [];
  let current = null;

  function currentTokenCount(obj) {
    if (!obj) return 0;
    return tokenCount(`## ${obj.title}\n${obj.content}`);
  }

  for (const s of sections) {
    const sec = { title: s.title, content: cleanText(s.content) };
    if (!current) {
      current = sec;
      continue;
    }
    const currentSmall = currentTokenCount(current) < minTokens;
    const candidate = {
      title: `${current.title} + ${sec.title}`,
      content: `${cleanText(current.content)}\n\n${cleanText(sec.content)}`,
    };
    if (currentSmall && currentTokenCount(candidate) <= maxTokens) {
      current = candidate;
    } else {
      out.push(current);
      current = sec;
    }
  }
  if (current) {
    if (out.length && currentTokenCount(current) < minTokens) {
      const prev = out.pop();
      const merged = {
        title: `${prev.title} + ${current.title}`,
        content: `${cleanText(prev.content)}\n\n${cleanText(current.content)}`,
      };
      if (currentTokenCount(merged) <= maxTokens) out.push(merged);
      else { out.push(prev); out.push(current); }
    } else {
      out.push(current);
    }
  }
  return out;
}

function formatSpecItems(items) {
  const lines = [];
  for (const s of items) {
    const name = cleanText(s?.name);
    const value = cleanText(s?.value);
    if (!name && !value) continue;
    if (toArray(s?.items).length) {
      lines.push(`- ${name}: ${value}`);
      for (const item of toArray(s.items).map(cleanText).filter(Boolean)) lines.push(`  - ${item}`);
    } else {
      lines.push(`- ${name}${name && value ? ': ' : ''}${value}`);
    }
  }
  return cleanText(lines.join('\n'));
}

function clearSpecSections(specs) {
  const arr = toArray(specs).filter(s => s && typeof s === 'object');
  const withSection = arr.filter(s => cleanText(s.section));
  if (!withSection.length) return [];

  const order = [];
  const groups = new Map();
  for (const s of arr) {
    const section = cleanText(s.section) || 'General';
    if (!groups.has(section)) { groups.set(section, []); order.push(section); }
    groups.get(section).push(s);
  }

  return order.map(section => ({
    title: section,
    content: formatSpecItems(groups.get(section)),
  })).filter(s => s.content);
}

function buildSpecsFallback(p) {
  const specsText = cleanText(p.specs_text);
  if (specsText) return specsText;
  const arr = toArray(p.specs).filter(s => s && typeof s === 'object');
  if (!arr.length) return '';
  return cleanText(`# Especificaciones técnicas\n${formatSpecItems(arr)}`);
}

function addOverview(rows, p, metadata) {
  const body = buildOverviewBody(p);
  addChunk(rows, p, 'overview', null, body, metadata, 'product', null);
}

function addDescription(rows, p, metadata, overviewBody) {
  const desc = cleanText(p.description);
  if (tokenCount(desc) < MIN_TOKENS) return;
  if (overlapRatio(desc, overviewBody) >= 0.78) return;
  addChunk(rows, p, 'description', null, desc, metadata, 'product', null);
}

function addFeatures(rows, p, metadata, compatibilityText, variantsText) {
  let text = cleanText(p.features_text);
  if (!text) return;
  text = removeH2Sections(text, [
    compatibilityText ? [/compatibilidad/i, /homolog/i] : null,
    variantsText ? [/variantes/i, /modelos/i] : null,
  ]);
  if (tokenCount(text) < MIN_TOKENS) return;

  const fullContent = withProductPrefix(p, text, null);
  if (tokenCount(fullContent) <= MAX_TOKENS) {
    rows.push(rowBase(p, 'features', null, fullContent, metadata, 'product'));
    return;
  }

  const sections = mergeSmallSections(splitH2Sections(text).filter(s => tokenCount(s.content) >= 5), 30, MAX_TOKENS);
  for (const s of sections) {
    addChunk(rows, p, 'features', s.title, s.content, metadata, 'product', s.title);
  }
}

function addSpecs(rows, p, metadata) {
  const sections = clearSpecSections(p.specs);
  if (sections.length) {
    const merged = mergeSmallSections(sections, 100, MAX_TOKENS);
    for (const s of merged) addChunk(rows, p, 'spec_section', s.title, s.content, metadata, 'product', s.title);
    return;
  }

  const fallback = buildSpecsFallback(p);
  if (tokenCount(fallback) < MIN_TOKENS) return;
  const fullContent = withProductPrefix(p, fallback, null);
  if (tokenCount(fullContent) <= MAX_TOKENS) {
    rows.push(rowBase(p, 'specs', null, fullContent, metadata, 'product'));
  } else {
    const sectionsFromText = splitH2Sections(fallback);
    if (sectionsFromText.length > 1) {
      for (const s of mergeSmallSections(sectionsFromText, 100, MAX_TOKENS)) {
        addChunk(rows, p, 'specs', s.title, s.content, metadata, 'product', s.title);
      }
    } else {
      addChunk(rows, p, 'specs', 'Especificaciones', fallback, metadata, 'product', 'Especificaciones');
    }
  }
}

function padIfShort(body, kind, p) {
  let text = cleanText(body);
  if (!text) return '';
  if (tokenCount(withProductPrefix(p, text, null)) >= MIN_TOKENS) return text;

  const product = cleanText(p.name) || 'este producto';
  if (kind === 'compatibility') {
    text += `\n\nEstas son las compatibilidades, homologaciones, marcas, modelos, países o certificaciones asociadas con ${product}, útiles para responder consultas de compatibilidad.`;
  } else if (kind === 'variants') {
    text += `\n\nEstas son las variantes, modelos o diferencias relevantes registradas para ${product}, útiles para comparar versiones o referencias comerciales.`;
  }
  return cleanText(text);
}

function addCompatibility(rows, p, metadata, compatibilityText) {
  const text = padIfShort(compatibilityText, 'compatibility', p);
  if (!text) return;
  addChunk(rows, p, 'compatibility', null, text, metadata, 'product', null);
}

function addVariants(rows, p, metadata, variantsText) {
  const text = padIfShort(variantsText, 'variants', p);
  if (!text) return;
  addChunk(rows, p, 'variants', null, text, metadata, 'product', null);
}

function addSoftware(rows, p, seenSoftware) {
  const softwareId = p.software_id;
  const text = cleanText(p.software_texto ?? p.software_description_text ?? p.software?.description_text);
  if (!softwareId || !p.is_software_canonical || !text || seenSoftware.has(String(softwareId))) return;
  seenSoftware.add(String(softwareId));
  const metadata = buildSoftwareMetadata(p);
  addChunk(rows, p, 'software', cleanText(p.software_nombre) || null, text, metadata, 'software', 'Software');
}

function buildRows(products) {
  const rows = [];
  const seenSoftware = new Set();
  const diagnostics = {
    products_received: products.length,
    products_with_compatibility_field: 0,
    products_with_compatibility_fallback_section: 0,
    products_with_variants_field: 0,
    products_with_relevant_variants: 0,
    products_with_variants_discarded_as_noise: 0,
    software_canonical_chunks: 0,
    chunk_counts_by_type: {},
    compatibility_product_ids: [],
    variant_product_ids: [],
    discarded_variant_product_ids: [],
    warnings: [],
  };

  for (const p of products) {
    if (p.id === undefined || !p.name) {
      diagnostics.warnings.push(`Producto omitido por falta de id/name: ${JSON.stringify(p).slice(0, 150)}`);
      continue;
    }

    const metadata = buildProductMetadata(p);
    const overviewBody = buildOverviewBody(p);
    const structuredCompatibility = buildCompatibilityText(p.compatibility);
    const fallbackCompatibility = extractH2Section(p.features_text, [/compatibilidad/i, /homolog/i]);
    const compatibilityText = structuredCompatibility || fallbackCompatibility;

    if (structuredCompatibility) {
      diagnostics.products_with_compatibility_field += 1;
      diagnostics.compatibility_product_ids.push(p.id);
    } else if (fallbackCompatibility) {
      diagnostics.products_with_compatibility_fallback_section += 1;
      diagnostics.compatibility_product_ids.push(p.id);
    }

    const rawVariantsText = buildVariantsText(p.variants, p);
    const fallbackVariants = extractH2Section(p.features_text, [/variantes/i, /modelos/i]);
    const fallbackRelevantVariants = buildVariantsText(fallbackVariants ? fallbackVariants.split('\n').filter(l => /^-\s+/.test(l)).map(l => l.replace(/^-\s+/, '')) : [], p);
    const variantsText = rawVariantsText || fallbackRelevantVariants;

    if (toArray(p.variants).filter(Boolean).length) diagnostics.products_with_variants_field += 1;
    if (variantsText) {
      diagnostics.products_with_relevant_variants += 1;
      diagnostics.variant_product_ids.push(p.id);
    } else if (toArray(p.variants).filter(Boolean).length) {
      diagnostics.products_with_variants_discarded_as_noise += 1;
      diagnostics.discarded_variant_product_ids.push(p.id);
    }

    addOverview(rows, p, metadata);
    addDescription(rows, p, metadata, overviewBody);
    addFeatures(rows, p, metadata, compatibilityText, variantsText);
    addSpecs(rows, p, metadata);
    addCompatibility(rows, p, metadata, compatibilityText);
    addVariants(rows, p, metadata, variantsText);
    const beforeSoftware = rows.length;
    addSoftware(rows, p, seenSoftware);
    if (rows.length > beforeSoftware) diagnostics.software_canonical_chunks += rows.length - beforeSoftware;
  }

  // --- Identidad estable del chunk: source_key ordinal, sin texto libre -------
  // El titulo mergeado de spec_section ('Interfaz celular + Interfaz Ethernet + ...')
  // cambiaba con el repacking por tokens en cada edicion -> el source_key cambiaba ->
  // el diff borraba+reinsertaba (churn) y dejaba huerfanos (conteos que no cuadran).
  // Se re-deriva source_key como ordinal estable por (source_type, id, chunk_type)
  // en orden de aparicion. El titulo legible se conserva intacto en section_name.
  if (INCLUDE_LOGICAL_KEY) {
    const __keyCounters = new Map();
    for (const row of rows) {
      const __ownerId = row.product_id ?? row.software_id ?? 'null';
      const __bucket = `${row.source_type}:${__ownerId}:${row.chunk_type}`;
      const __idx = __keyCounters.get(__bucket) ?? 0;
      __keyCounters.set(__bucket, __idx + 1);
      row.source_key = `${__bucket}:${__idx}`;
    }
  }

  for (const row of rows) diagnostics.chunk_counts_by_type[row.chunk_type] = (diagnostics.chunk_counts_by_type[row.chunk_type] || 0) + 1;
  diagnostics.total_chunks = rows.length;
  diagnostics.max_tokens = rows.reduce((m, r) => Math.max(m, tokenCount(r.content)), 0);
  diagnostics.min_tokens = rows.reduce((m, r) => Math.min(m, tokenCount(r.content)), Infinity);
  diagnostics.too_large_chunks = rows.filter(r => tokenCount(r.content) > MAX_TOKENS).map(r => logicalKey(r.source_type, r.product_id, r.software_id, r.chunk_type, r.section_name));
  diagnostics.too_small_chunks = rows.filter(r => tokenCount(r.content) < MIN_TOKENS).map(r => `${logicalKey(r.source_type, r.product_id, r.software_id, r.chunk_type, r.section_name)} (${tokenCount(r.content)})`);
  return { rows, diagnostics };
}

// n8n: Run Once for All Items
const inputItems = typeof $input !== 'undefined' ? $input.all() : [];
const products = collectProducts(inputItems);
const { rows, diagnostics } = buildRows(products);

if (OUTPUT_MODE === 'diagnostics') {
  return [{ json: diagnostics }];
}

return rows.map(row => ({ json: row }));

// Pasa TODOS los atributos de cada fila excepto embedding,
// para no meter el vector(3072) al Merge (alasql) y evitar "Isolate is disposed".
return $input.all().map(item => {
  const { embedding, ...rest } = item.json;
  return { json: rest };
});

const categories = $('Postgres: categories').all().map(item => item.json);
const products = $('Postgres: products').all().map(item => item.json);
const productSpecs = $('Postgres: product_specs').all().map(item => item.json);

function isEmptyObject(value) {
  return (
    value !== null &&
    typeof value === 'object' &&
    !Array.isArray(value) &&
    Object.keys(value).length === 0
  );
}

function isMissingSpecsNormalized(value) {
  return (
    value === null ||
    value === undefined ||
    isEmptyObject(value)
  );
}

function hasSpecs(value) {
  if (value === null || value === undefined) return false;

  if (Array.isArray(value)) {
    return value.length > 0;
  }

  if (typeof value === 'object') {
    return Object.keys(value).length > 0;
  }

  if (typeof value === 'string') {
    return value.trim() !== '';
  }

  return true;
}

const categoriesById = new Map();
for (const category of categories) {
  categoriesById.set(category.id, category);
}

const productsById = new Map();
for (const product of products) {
  productsById.set(product.id, product);
}

const categoryPayloads = new Map();

for (const ps of productSpecs) {
  if (!isMissingSpecsNormalized(ps.specs_normalized)) continue;
  if (!hasSpecs(ps.specs)) continue;
  // if (!hasSpecs(ps.specs) && !hasSpecs(ps.table_specs)) continue;

  const product = productsById.get(ps.product_id);
  if (!product) continue;

  const category = categoriesById.get(product.category_id);
  if (!category) continue;

  if (!categoryPayloads.has(category.id)) {
    categoryPayloads.set(category.id, {
      category_id: category.id,
      rows: [],
    });
  }

  const payload = categoryPayloads.get(category.id);

  payload.rows.push({
    category_name: category.name,
    id: product.id,
    product_name: product.name,
    product_slug: product.slug,
    brand: product.brand,
    model: product.model,
    category_id: product.category_id,
    specs: ps.specs,
    // table_specs: ps.table_specs,
    specs_normalized: ps.specs_normalized,
  });
}

const results = Array.from(categoryPayloads.values())
  .map(payload => {
    payload.rows.sort((a, b) => {
      if (a.id === b.id) return 0;
      return a.id > b.id ? 1 : -1;
    });

    return payload;
  })
  .sort((a, b) => {
    if (a.category_id === b.category_id) return 0;
    return a.category_id > b.category_id ? 1 : -1;
  });

if (results.length === 0) {
  return [
    {
      json: {
        category_id: null,
        rows: [],
      },
    },
  ];
}

return results.map(payload => ({
  json: payload,
}));
